export const 致雨玉符 = (bi) => {
    const u = bi.u, k = 2.3;
    const X = (c) => (c - 4.9) * k;
    const Z = (r) => (r - 0.25) * k + 1.0;
    const 抖 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 摺 = (x0, x1, rT, rB, n, 左起 = true, 寬 = 0.4) => 抖(pa => {
        const p = n > 1 ? (rB - rT) / (n - 1) : 0;
        let dir = 左起 ? 1 : -1, y = rT;
        pa.M(X(dir > 0 ? x0 : x1), Z(y));
        for (let i = 0; i < n; i++) {
            const xe = dir > 0 ? x1 : x0;
            if (i < n - 1) {
                pa.L(X(xe - dir * p * 0.35), Z(y));
                pa.C(X(xe + dir * p * 1.05), Z(y - p * 0.05), X(xe + dir * p * 1.05), Z(y + p * 1.05), X(xe - dir * p * 0.35), Z(y + p));
                y += p;
                dir = -dir;
            }
            else
                pa.L(X(xe), Z(y));
        }
    }, 寬);
    // 粗鉤入筆＋頭三疊帶
    抖(p => p.M(X(0.15), Z(0.55)).C(X(0.3), Z(0.3), X(0.7), Z(0.25), X(0.98), Z(0.42)), 0.5);
    摺(0.3, 2.5, 0.6, 2.5, 5);
    抖(p => p.M(X(2.55), Z(1.75)).C(X(3.1), Z(1.8), X(3.15), Z(2.2), X(2.62), Z(2.3)), 0.38);
    摺(3.7, 6.5, 0.6, 2.9, 7);
    摺(6.8, 9.3, 0.7, 2.7, 6);
    // 左長疊帶（七摺・回結・四摺）
    摺(0.3, 4.4, 2.7, 6.0, 7);
    抖(p => p.M(X(4.35), Z(6.35))
        .C(X(2.4), Z(6.3), X(2.25), Z(6.85), X(3.3), Z(6.9))
        .C(X(4.35), Z(6.95), X(4.3), Z(7.35), X(3.2), Z(7.4)), 0.4);
    摺(0.3, 4.4, 7.55, 9.6, 4);
    // 右段：三摺＋冂內摺＋波摺＋五摺
    摺(5.2, 9.2, 3.0, 4.4, 3);
    線(p => p.M(X(5.35), Z(4.55)).L(X(9.35), Z(4.5)).L(X(9.33), Z(6.2)), 0.4);
    線(p => p.M(X(9.05), Z(4.75)).L(X(8.75), Z(4.98)), 0.3);
    摺(5.35, 8.6, 4.9, 6.1, 3);
    抖(p => p.M(X(5.35), Z(6.62))
        .C(X(6.5), Z(6.45), X(7.5), Z(6.82), X(9.3), Z(6.62)), 0.4);
    摺(5.2, 9.3, 7.05, 9.6, 5);
    // 滿幅帶（丫剔・結點）
    摺(0.3, 9.5, 9.85, 11.35, 3);
    抖(p => p.M(X(4.45), Z(10.3)).L(X(4.75), Z(10.5)), 0.3);
    抖(p => p.M(X(4.45), Z(10.7)).L(X(4.75), Z(10.5)), 0.3);
    抖(p => p.M(X(0.45), Z(11.15)).C(X(0.68), Z(11.1), X(0.72), Z(11.3), X(0.5), Z(11.33)), 0.36);
    // 對疊帶
    摺(0.3, 4.5, 11.5, 13.9, 5);
    摺(5.2, 9.4, 11.5, 13.9, 5);
    // 左厂玄：厂＋玄帶＋人紋三重＋干莖＋北匕對
    線(p => p.M(X(0.85), Z(14.3)).L(X(3.6), Z(14.25)), 0.42);
    抖(p => p.M(X(0.95), Z(14.3)).C(X(0.6), Z(15.2), X(0.55), Z(16.4), X(0.85), Z(17.2)), 0.42);
    線(p => p.M(X(1.2), Z(14.95)).L(X(3.3), Z(14.9)), 0.36);
    for (const dz of [15.3, 15.75, 16.2]) {
        抖(p => p.M(X(2.25), Z(dz)).L(X(1.6), Z(dz + 0.45)), 0.34);
        抖(p => p.M(X(2.3), Z(dz)).L(X(2.95), Z(dz + 0.45)), 0.34);
    }
    線(p => p.M(X(2.6), Z(16.75)).L(X(2.58), Z(18.4)), 0.38);
    線(p => p.M(X(1.35), Z(17.4)).L(X(1.33), Z(18.5)), 0.36);
    抖(p => p.M(X(1.35), Z(18.1)).C(X(1.6), Z(18.3), X(1.8), Z(18.35), X(1.95), Z(18.25)), 0.34);
    線(p => p.M(X(3.5), Z(17.35)).L(X(3.48), Z(18.45)), 0.36);
    抖(p => p.M(X(3.5), Z(18.05)).C(X(3.75), Z(18.25), X(3.95), Z(18.3), X(4.1), Z(18.2)), 0.34);
    // 右段中低：三摺＋北匕對＋右臂
    摺(5.2, 9.4, 14.0, 15.6, 3);
    線(p => p.M(X(5.85), Z(15.75)).L(X(5.83), Z(17.0)), 0.36);
    抖(p => p.M(X(5.85), Z(16.6)).C(X(6.1), Z(16.8), X(6.3), Z(16.85), X(6.45), Z(16.75)), 0.34);
    線(p => p.M(X(7.35), Z(15.7)).L(X(7.33), Z(16.95)), 0.36);
    抖(p => p.M(X(7.35), Z(16.55)).C(X(7.6), Z(16.75), X(7.8), Z(16.8), X(7.95), Z(16.7)), 0.34);
    抖(p => p.M(X(9.4), Z(14.1)).L(X(9.38), Z(17.2)), 0.4);
    // 大形帶（雙桁中莖人腳・右臂）
    線(p => p.M(X(0.9), Z(17.75)).L(X(9.35), Z(17.68)), 0.42);
    線(p => p.M(X(1.0), Z(18.45)).L(X(9.3), Z(18.38)), 0.42);
    線(p => p.M(X(4.8), Z(17.8)).L(X(4.78), Z(19.0)), 0.4);
    抖(p => p.M(X(4.78), Z(18.9)).C(X(4.4), Z(19.3), X(4.1), Z(19.5), X(3.95), Z(19.6)), 0.38);
    抖(p => p.M(X(4.82), Z(18.9)).C(X(5.2), Z(19.3), X(5.5), Z(19.5), X(5.65), Z(19.6)), 0.38);
    抖(p => p.M(X(9.35), Z(17.75)).L(X(9.33), Z(19.3)), 0.4);
    // 底帶（滿幅三摺＋對摺）＋己足對
    摺(0.3, 9.4, 19.8, 21.4, 3);
    摺(0.3, 4.3, 21.55, 23.6, 4);
    摺(4.9, 9.3, 21.55, 23.6, 4);
    抖(p => p.M(X(0.6), Z(23.8))
        .C(X(0.5), Z(24.35), X(0.4), Z(24.75), X(0.45), Z(25.0))
        .C(X(0.5), Z(25.35), X(0.9), Z(25.28), X(0.9), Z(24.95))
        .C(X(0.9), Z(24.72), X(0.65), Z(24.72), X(0.6), Z(24.9)), 0.4);
    抖(p => p.M(X(9.2), Z(23.75))
        .C(X(9.32), Z(24.3), X(9.42), Z(24.7), X(9.38), Z(24.95))
        .C(X(9.33), Z(25.3), X(8.93), Z(25.22), X(8.95), Z(24.9))
        .C(X(8.97), Z(24.67), X(9.2), Z(24.68), X(9.22), Z(24.86)), 0.4);
};
